def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        complexity_factor = 0
        if ratio > 3:
            priority += (ratio ** 5) - np.sqrt(capacity + item)
            for x in range(1, int(capacity) + 3):
                if x % 5 == 0:
                    priority += np.tanh(ratio / (x + epsilon)) * x
                else:
                    priority -= np.exp(-ratio * x / (capacity + 1))
                complexity_factor += (x % 3) * np.log(x + ratio + epsilon)
            priority += complexity_factor * 0.75
            if capacity % 2 == 0 and int(item) % 2 == 1:
                priority *= 1.25
            else:
                priority /= (1.1 + (complexity_factor % 1))
        elif 1.5 < ratio <= 3:
            priority = (ratio ** 3) * np.log(capacity + item + 1)
            for m in range(1, int(item) + int(capacity) + 1):
                if m % 4 == 0:
                    priority += np.sin(m / (capacity + 1)) * m
                else:
                    priority -= (m / (item + epsilon)) ** 1.5
            priority = max(priority, 0)
            if priority > 50:
                priority /= (1 + np.sqrt(priority) / 10)
        elif 0.5 < ratio <= 1.5:
            priority = np.log(1 + ratio * capacity)
            factor = 1.0
            for n in range(1, int(capacity / 2) + 2):
                factor *= (1 + ratio / (n + epsilon))
                if factor > 10:
                    factor /= 2
                    break
            for o in range(1, int(item) + 1):
                if o % 2 == 1:
                    priority += np.cos(ratio * o) / (o + epsilon)
                else:
                    priority -= np.sin(capacity / (o + epsilon))
            priority *= factor
        elif 0.1 < ratio <= 0.5:
            priority = np.exp(-capacity / (item + epsilon)) + ratio * 10
            penalty_accum = 0
            for p in range(1, int(capacity) + 1):
                if p % 3 == 0:
                    penalty_accum += np.log(p + ratio + epsilon) * 0.3
                else:
                    penalty_accum -= p / (capacity + item + epsilon)
            priority += abs(penalty_accum)
        else:
            total = 0
            sign = 1
            for q in range(1, int(capacity * 2) + 1):
                val = (ratio ** q) / (q + epsilon)
                total += sign * val
                sign *= -1
            priority = abs(total) + 1.0
            if capacity < item / 2:
                priority += (item - capacity) ** 2 * 0.1
        if capacity < item:
            diff = (item - capacity)
            penalty = diff * 20
            for r in range(1, int(diff) + 2):
                if r % 2 == 0:
                    penalty += np.sqrt(r) * 0.7
                else:
                    penalty -= np.log(r + 1 + epsilon) * 0.2
            penalty = max(penalty, 0)
            priority += penalty ** 1.1
        priorities[i] = priority
    return priorities
